    display(data_a.describe())

summary = []
for name, data in [('Room A', data_a), ('Room B', data_b)]:
    if len(data) > 0:
        summary.append({
            'Room': name,
            'Records': len(data),
            'Temp Mean': round(data['temperature'].mean(), 2),
            'Temp Std': round(data['temperature'].std(), 2),
            'Temp Min': round(data['temperature'].min(), 2),
            'Temp Max': round(data['temperature'].max(), 2),
            'Humid Mean': round(data['humidity'].mean(), 2),
            'Humid Std': round(data['humidity'].std(), 2),
        })

if summary:
    summary_df = pd.DataFrame(summary)
    display(summary_df)
else:
    print('No data available. Run the Sensor Simulator first.')
